var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して彼女を呼び出すと、約束の場所で待っているとの返事が返ってきた。","ENG":"Having decided that, you called her. She answered she'd be waiting for you at the place you promised to meet.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"후훗, 처음 화보집 모델 제안을 받아주셨을 땐 이렇게 열심히 촬영에 임해주실 줄 몰랐어요.","JPN":"ふふっ、初めて写真集のモデルの提案を引き受けてくれた時は、ここまで真剣に撮影に取り組んでくれると思わなかったんです。","ENG":"Heh, I had no idea you'd agree so eagerly to join me for this photoshoot.","TWN":"呵呵，您剛開始接受寫真集的模特提議時，我沒想到您會這麼認真地拍攝。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"목 위로만 사진에 나오지 않으면 된다고 해서 가벼운 마음이시겠니 했는데......","JPN":"顔が写らなければいいと言っていたので、軽い気持ちで参加したのだと思いましたが……","ENG":"I thought you won't be taking this too seriously since you said I just need to keep your face out of the photo...","TWN":"我猜可能是因為脖子以上的部分都不會出現在照片中，所以您的心態比較輕鬆吧……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"무척 적극적으로 협조해주셔서, 덕분에 괜찮은 장면이 많이 나왔네요.","JPN":"とても積極的にご協力いただいたおかげで、\\nいいものがたくさん撮れました。","ENG":"But you've been very cooperative. Thanks to you, we got a lot of great shots.","TWN":"多虧了您的積極配合，我拍到了很多不錯的畫面。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"네? 가벼운 마음으로 협조하는 게 아니라 진지하게 임하고 있다니......","JPN":"はい？軽い気持ちで協力しているんじゃなくて、真剣に取り組んでいるんだと……","ENG":"Sorry? You are... taking this very seriously?","TWN":"嗯？不是以輕鬆的心態，而是很認真地在拍攝……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"후후, 여자 마음으로 그렇게 장난 치시긴가요? 의외로 짓궂으시네요.","JPN":"ふふ、女心を弄んでいますか？意外と意地悪ですね。","ENG":"Hah hah, you shouldn't toy around with a girl's heart like that. You're a lot naughtier than I thought.","TWN":"呵呵，您是在玩弄女人心嗎？您還真是頑皮啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"하아, 갑자기 덥네요. 바람을 좀 불러와야겠어요.","JPN":"ふう、急に暑くなりました。少し風に当たって来ます。","ENG":"Phew... It's getting a little hot now. I'd better round up a breeze.","TWN":"哈啊，突然好熱啊。我得吹吹風才行。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"흠! 그럼 이번 허그 씬 작업만 마치고 오늘은 이쯤에서 마무리 짓도록 하죠.","JPN":"こほん！今日のところはハグシーンだけ撮影して終わりたいと思います。","ENG":"Hmm. Let's call it a day after this hug scene.","TWN":"來吧！那完成這次的擁抱場面後，今天就到此為止吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"제가 사장님의 목덜미를 감쌀 테니......","JPN":"私が社長の顔は隠しますから……","ENG":"I'll put my arms around your neck...","TWN":"我會摟住老闆的脖子……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"실례지만 적극적인 포옹 한 번 괜찮으시겠어요?","JPN":"失礼ですが、一度積極的なハグをお願いできますか？","ENG":"Would you mind giving me a big hug for the photo?","TWN":"抱歉，能請您抱得再積極一點嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"후훗, 원래대로라면 리얼리티를 살리기 위해 입맞춤까지도 이어가려 했지만 생략하죠.","JPN":"ふふっ、本来ならリアリティを出すためにキスもする予定でしたが、それは省略しましょう。","ENG":"Heh, I was going to go with a kiss to make it extra realistic, but decided to skip over that for now.","TWN":"呵呵，本來為了拍攝效果，後面還要接吻的，但我們就算了吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"사장님 요청도 있으니, 어차피 얼굴은 나오지 않을 테니까요.","JPN":"社長の要望もありますし、どうせ顔は出ませんから。","ENG":"You asked me to keep your face out of the photo anyway.","TWN":"老闆也是這麼要求的，而且反正老闆也不會露臉。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"아하하, 왜 갑자기 시무룩한 표정을 짓고 그러세요~ 귀여우시긴.","JPN":"あはは、どうして急に落ち込んだりするんですか～。可愛いですね。","ENG":"Hah hah! Why do you look so disappointed? Aww, aren't you cute.","TWN":"啊哈哈，你為什麼突然擺出鬱悶的表情啊～怪可愛的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"......기회는 다음 번에도 있잖아요? 이번 촬영이 끝은 아니니까.","JPN":"……チャンスはまだありますよ。次の撮影もありますから。","ENG":"I'm sure you'll have another chance next time... This photoshoot isn't the end.","TWN":"……下次還有機會嘛！這場拍攝又不是最後一次。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CATHY_CIVIL_WEDDING_NULL","text":{"KOREA":"아까도 말씀 드렸다시피, 목 위로는 편집이라서 뭘 해도 아무도 모른다고요?","JPN":"先ほども話しましたが、顔はカットするので何をしたって誰もわかりませんよ。","ENG":"Like I said though, nobody will know what happens above your neckline.","TWN":"就像我剛才說的那樣，脖子上面會剪輯掉，不管做什麼都沒人知道喔？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_WEDDING_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};